//! Per-proto-service Server dispatch types, generated by the
//! `service_server` proc-macro. Invoked from this crate (not from
//! `axl-proto`) because the generated code references both `axl_proto`
//! types and `axl_runtime` types — invoking it here lets both resolve.
//! `lib.rs` aliases the crate as `axl_runtime` via `extern crate self`
//! so the macro's `::axl_runtime::...` paths resolve from inside the
//! crate.
//!
//! In v1 each RPC method body is `Status::unimplemented` — the
//! Starlark-from-tokio dispatch (creating a fresh `Evaluator` on a tokio
//! worker, invoking the stored callable, marshalling proto<->Starlark)
//! lands in a focused follow-up. The structural pieces compile end-to-end
//! now so the API surface is testable.

use starlark::environment::GlobalsBuilder;

#[starbuf_derive::service_server(
    proto_path = "build.bazel.remote.execution.v2.Capabilities",
    server_trait = "::axl_proto::build::bazel::remote::execution::v2::capabilities_server::Capabilities",
    tonic_server = "::axl_proto::build::bazel::remote::execution::v2::capabilities_server::CapabilitiesServer",
    methods(
        name = "GetCapabilities",
        method = "get_capabilities",
        request = "::axl_proto::build::bazel::remote::execution::v2::GetCapabilitiesRequest",
        response = "::axl_proto::build::bazel::remote::execution::v2::ServerCapabilities",
        request_streaming = false,
        response_streaming = false,
    )
)]
pub struct Capabilities;

